package problems;

public class ContainerWithMostWater {

    public static void main(String[] args) {
        int[] heights = {1, 8, 6, 2, 5, 4, 8, 3, 7};
        System.out.println("Max water container can hold is " + maxWater(heights));
    }

    /**
     * Two-pointer approach to find maximum water container.
     * 
     * Time: O(n), Space: O(1)
     * 
     * Algorithm:
     * - Start with widest container (left=0, right=n-1)
     * - Calculate area with current pointers
     * - Move pointer with smaller height inward (can't improve with same height)
     * - Continue until pointers meet
     * 
     * Intuition: Width decreases as we move inward, so we need greater
     * height to potentially get larger area.
     */
    public static int maxWater(int[] height) {
        int max = 0;
        int left = 0;
        int right = height.length - 1;

        while (left < right) {
            // Calculate current container area
            int width = right - left;
            int area = Math.min(height[right], height[left]) * width;
            max = Math.max(max, area);

            // Move pointer with smaller height
            if (height[left] <= height[right]) {
                left++;
            } else {
                right--;
            }
        }

        return max;
    }
}

// Example 1:
// Input: height = [1,8,6,2,5,4,8,3,7]
// Output: 49
// Explanation: Lines at index 1 (height=8) and index 8 (height=7)
// form container with area = min(8,7) * (8-1) = 7 * 7 = 49

// Example 2:
// Input: height = [1,1]
// Output: 1
